import React, { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { registerUser } from "../services/api";

function Register() {
  const navigate = useNavigate();

  const [formData, setFormData] = useState({
    username: "",
    password: "",
    email: "",
    phone: "",
  });

  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    if (!formData.username || !formData.password) {
      setError("Tên đăng nhập và mật khẩu là bắt buộc.");
      return;
    }

    setLoading(true);
    try {
      const result = await registerUser(formData);
      setMessage(result.message || "Đăng ký thành công! Đang chuyển đến đăng nhập...");
      setTimeout(() => navigate("/login"), 900);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page">
      {/* LEFT — Branding */}
      <div className="auth-left">
        <Link to="/" className="auth-left-logo">
          <span className="auth-left-logo-mark">⚽</span>
          <span className="auth-left-logo-text">
            Đặt <span>Sân Bóng</span>
          </span>
        </Link>

        <div className="auth-left-body">
          <span className="auth-left-badge">🆕 Tạo tài khoản mới</span>
          <h1>Bắt đầu hành trình bóng đá của bạn</h1>
          <p>
            Đăng ký hoàn toàn miễn phí để tham gia cộng đồng bóng đá, đặt sân
            và kết nối với hàng nghìn người chơi khác trên nền tảng.
          </p>

          <div className="auth-features">
            <div className="auth-feature-item">
              <div className="auth-feature-icon">🆓</div>
              <div className="auth-feature-text">
                <strong>Đăng ký miễn phí</strong>
                <span>Không cần phí, tạo tài khoản chỉ trong 1 phút</span>
              </div>
            </div>
            <div className="auth-feature-item">
              <div className="auth-feature-icon">👤</div>
              <div className="auth-feature-text">
                <strong>Hồ sơ người chơi tự động</strong>
                <span>Hệ thống tự tạo hồ sơ cầu thủ sau khi đăng ký</span>
              </div>
            </div>
            <div className="auth-feature-item">
              <div className="auth-feature-icon">🛡️</div>
              <div className="auth-feature-text">
                <strong>Bảo mật thông tin</strong>
                <span>Dữ liệu của bạn được mã hóa và bảo vệ an toàn</span>
              </div>
            </div>
          </div>
        </div>

        <div className="auth-left-footer">
          © 2026 ĐặtSânBóng · Nền tảng bóng đá cộng đồng hiện đại
        </div>
      </div>

      {/* RIGHT — Form */}
      <div className="auth-right">
        <div className="auth-form-box">
          <h2>Đăng ký tài khoản</h2>
          <p className="auth-subtitle">
            Điền thông tin cơ bản để tạo tài khoản mới và bắt đầu trải nghiệm.
          </p>

          <form className="auth-form" onSubmit={handleSubmit}>
            <div className="auth-form-group">
              <label htmlFor="username">
                Tên đăng nhập <span style={{ color: "#dc2626" }}>*</span>
              </label>
              <input
                id="username"
                type="text"
                name="username"
                value={formData.username}
                onChange={handleChange}
                placeholder="Nhập tên đăng nhập (bắt buộc)"
                autoComplete="username"
              />
            </div>

            <div className="auth-form-group">
              <label htmlFor="password">
                Mật khẩu <span style={{ color: "#dc2626" }}>*</span>
              </label>
              <input
                id="password"
                type="password"
                name="password"
                value={formData.password}
                onChange={handleChange}
                placeholder="Nhập mật khẩu (bắt buộc)"
                autoComplete="new-password"
              />
            </div>

            <div className="auth-form-group">
              <label htmlFor="email">Email</label>
              <input
                id="email"
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                placeholder="Nhập email (không bắt buộc)"
                autoComplete="email"
              />
            </div>

            <div className="auth-form-group">
              <label htmlFor="phone">Số điện thoại</label>
              <input
                id="phone"
                type="tel"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="Nhập số điện thoại (không bắt buộc)"
                autoComplete="tel"
              />
            </div>

            <button
              type="submit"
              className="auth-submit-btn"
              disabled={loading}
            >
              {loading ? "Đang tạo tài khoản..." : "🎉 Đăng ký miễn phí"}
            </button>
          </form>

          {message && (
            <div className="auth-alert-success" style={{ marginTop: "16px" }}>
              ✅ {message}
            </div>
          )}
          {error && (
            <div className="auth-alert-error" style={{ marginTop: "16px" }}>
              ⚠️ {error}
            </div>
          )}

          <div className="auth-divider" style={{ margin: "20px 0 16px" }}>
            hoặc
          </div>

          <p className="auth-alt-link">
            Đã có tài khoản?{" "}
            <Link to="/login">Đăng nhập ngay →</Link>
          </p>

          <p style={{ marginTop: "12px", textAlign: "center" }}>
            <Link to="/" style={{ color: "#66756d", fontSize: "14px" }}>
              ← Về trang chủ
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
}

export default Register;
